mapper.select:
SELECT *
FROM devices
WHERE product_id = #{productId}
  AND device_name = #{deviceName}
  AND deleted_at IS NULL
LIMIT 1

SELECT d.id, d.device_name AS deviceName, d.nickname, d.product_id AS productId, p.product_key AS productKey, p.name AS productName, d.tenant_id AS tenantId, d.project_id AS projectId, d.status, d.online_status AS onlineStatus FROM devices d LEFT JOIN products p ON p.id = d.product_id WHERE d.deleted_at IS NULL AND d.id IN
#{id}
ORDER BY d.id

SELECT d.id, d.device_name AS deviceName, d.nickname, d.product_id AS productId, p.product_key AS productKey, p.name AS productName, d.tenant_id AS tenantId, d.project_id AS projectId, d.status, d.online_status AS onlineStatus FROM devices d LEFT JOIN products p ON p.id = d.product_id WHERE d.deleted_at IS NULL AND d.tenant_id = #{ownerTenantId}
AND d.product_id IN
#{productId}
AND d.device_name IN
#{deviceName}
ORDER BY d.id
